 1	import * as React from 'react';
 2	import {
 3	  useParams,
 4	  useLocation,
 5	  useNavigate,
 6	} from 'react-router-dom-v5-compat';
 7	
 8	import { usePacData } from './hooks/usePacData';
 9	import PacForm from './PacForm';
10	import PacOverview from './PacOverview';
11	import {
12	  useAccessReview,
13	  useFlag,
14	} from '@openshift-console/dynamic-plugin-sdk';
15	import { FLAG_OPENSHIFT_PIPELINE, PIPELINE_NAMESPACE } from '../../consts';
16	import { AccessDenied, ErrorPage404 } from '../common/error';
17	import { LoadingBox } from '../status/status-box';
18	
19	const PacPage: React.FC = () => {
20	  const location = useLocation();
21	  const navigate = useNavigate();
22	  const queryParams = new URLSearchParams(location.search);
23	  const isPipelinesEnabled = useFlag(FLAG_OPENSHIFT_PIPELINE);
24	  const [isAdmin, isAdminCheckLoading] = useAccessReview({
25	    namespace: PIPELINE_NAMESPACE,
26	    verb: 'create',
27	    resource: 'secrets',
28	  });
29	  const code = queryParams.get('code');
30	  const { ns: namespace } = useParams();
31	
32	  React.useEffect(() => {
33	    if (isPipelinesEnabled && namespace !== PIPELINE_NAMESPACE) {
34	      navigate(`/pac/ns/${PIPELINE_NAMESPACE}`);
35	    }
36	  }, [isPipelinesEnabled, namespace, navigate]);
37	
38	  const { loaded, secretData, loadError, isFirstSetup } = usePacData(code);
39	
40	  if (!isPipelinesEnabled) {
41	    return <ErrorPage404 />;
42	  }
43	
44	  if (!isAdminCheckLoading && !isAdmin) {
45	    return <AccessDenied />;
46	  }
47	
48	  return (
49	    <>
50	      {!loaded ? (
51	        <LoadingBox />
52	      ) : loadError || secretData ? (
53	        <PacOverview
54	          namespace={namespace}
55	          secret={secretData}
56	          loadError={loadError}
57	          showSuccessAlert={isFirstSetup}
58	        />
59	      ) : (
60	        <PacForm namespace={namespace} />
61	      )}
62	    </>
63	  );
64	};
65	
66	export default PacPage;

